using ModelContextProtocol.Server;
using System.Text.Json;

namespace McpHttpServer;

[McpServerResource(UriTemplate = "config://app/settings", Name = "AppSettings",
    Description = "Returns the current application configuration")]
public class ConfigResource
{
    public static readonly Dictionary<string, object> Settings = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
        },
    };

    [McpServerResourceTemplate]
    public static McpServerResourceResponse GetSettings()
    {
        var json = JsonSerializer.Serialize(Settings, new JsonSerializerOptions { WriteIndented = true });
        return new McpServerResourceResponse(new ModelContextProtocol.Protocol.Types.ResourceContents[]
        {
            new ModelContextProtocol.Protocol.Types.TextResourceContents
            {
                Uri = "config://app/settings",
                MimeType = "application/json",
                Text = json,
            },
        });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer;

[McpServerToolType]
public static class ServerTools
{
    [McpServerTool(Name = "echo"), Description("Echoes back the input message")]
    public static string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";

    [McpServerTool(Name = "get_server_time"), Description("Returns the current UTC server time")]
    public static string GetServerTime()
        => DateTime.UtcNow.ToString("o");
}

